import { mkdir, rm, writeFile } from 'node:fs/promises';
import { join } from 'node:path';

const outputRoot = join('dist', 'docs');

await rm('dist', { recursive: true, force: true });
await mkdir(join(outputRoot, 'assets'), { recursive: true });
await mkdir(join(outputRoot, 'page'), { recursive: true });

function renderPage({ title, marker, content }) {
  return `<!doctype html>
<html lang="en">
  <head>
    <meta charset="utf-8" />
    <meta name="viewport" content="width=device-width, initial-scale=1" />
    <title>${title}</title>
    <link rel="stylesheet" href="/docs/assets/docs.css" />
  </head>
  <body>
    <main>
      <h1>${marker}</h1>
      <p>${content}</p>
      <nav>
        <a href="/">Frontend</a>
        <a href="/docs">Docs index</a>
        <a href="/docs/page">Docs page</a>
      </nav>
    </main>
  </body>
</html>
`;
}

await writeFile(
  join(outputRoot, 'index.html'),
  renderPage({
    title: 'Docs Index',
    marker: 'SERVICE_DOCS_STATIC_BUILD_INDEX',
    content: 'The docs service was generated by a build command.',
  })
);

await writeFile(
  join(outputRoot, 'page', 'index.html'),
  renderPage({
    title: 'Docs Page',
    marker: 'SERVICE_DOCS_STATIC_BUILD_PAGE',
    content: 'This nested docs route is served from dist/docs/page/index.html.',
  })
);

await writeFile(
  join(outputRoot, 'assets', 'docs.css'),
  `/* SERVICE_DOCS_STATIC_BUILD_CSS */
body {
  margin: 2rem;
  font-family: system-ui, sans-serif;
}
`
);
